package main

import (
	"container/heap"
)

type Edge struct {
	v, s, e int64
}

type State struct {
	time int64
	node int64
}

type PriorityQueue []*State

func (pq PriorityQueue) Len() int { return len(pq) }

func (pq PriorityQueue) Less(i, j int) bool { return pq[i].time < pq[j].time }

func (pq PriorityQueue) Swap(i, j int) {
	pq[i], pq[j] = pq[j], pq[i]
}

func (pq *PriorityQueue) Push(x interface{}) {
	*pq = append(*pq, x.(*State))
}

func (pq *PriorityQueue) Pop() interface{} {
	old := *pq
	n := len(old)
	item := old[n-1]
	*pq = old[0 : n-1]
	return item
}

func solve(n int64, edges [][]int64) int64 {
	adj := make([][]Edge, n)
	for _, e := range edges {
		u := e[0]
		v := e[1]
		s := e[2]
		e_end := e[3]
		adj[u] = append(adj[u], Edge{v, s, e_end})
	}

	dist := make([]int64, n)
	for i := range dist {
		dist[i] = -1
	}
	dist[0] = 0

	pq := make(PriorityQueue, 0)
	heap.Init(&pq)
	heap.Push(&pq, &State{time: 0, node: 0})

	for pq.Len() > 0 {
		state := heap.Pop(&pq).(*State)
		currentTime := state.time
		node := state.node

		if node == n-1 {
			return currentTime
		}

		if dist[node] < currentTime {
			continue
		}

		for _, edge := range adj[node] {
			var earliest int64
			if currentTime > edge.s {
				earliest = currentTime
			} else {
				earliest = edge.s
			}
			if earliest > edge.e {
				continue
			}
			newTime := earliest + 1
			if dist[edge.v] == -1 || newTime < dist[edge.v] {
				dist[edge.v] = newTime
				heap.Push(&pq, &State{time: newTime, node: edge.v})
			}
		}
	}

	return -1
}
